const body = $input.first().json.body;

if (!body.patient?.name || !body.date || !body.time) {
  throw new Error('Datos de reserva incompletos');
}

const [year, month, day] = body.date.split('-').map(Number);
const [hour, minute] = body.time.split(':').map(Number);
const durationMin = 60;
const startDate = new Date(year, month - 1, day, hour, minute);
const endDate = new Date(startDate.getTime() + durationMin * 60000);
const pad = n => String(n).padStart(2, '0');
const formatGCal = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}:00`;
const esc = s => String(s || '').replace(/'/g, "''").substring(0, 200);

const description = [
  `Paciente: ${body.patient.name}`,
  `Teléfono: ${body.patient.phone}`,
  `Email: ${body.patient.email || 'No proporcionado'}`,
  `Servicio: ${body.service}`,
  `Motivo: ${body.reason || 'No especificado'}`,
  `Paciente nuevo: ${body.patient.newPatient ? 'Sí' : 'No'}`,
  `---`,
  `Reservado via Nervia · ${body.timestamp}`
].join('\n');

return [{
  json: {
    ...body,
    gcal: {
      summary: `${body.service} — ${body.patient.name}`,
      description,
      startDateTime: formatGCal(startDate),
      endDateTime: formatGCal(endDate),
      timeZone: 'Europe/Madrid',
      attendeeEmail: body.patient.email,
      calendarId: body.calendarId || 'primary'
    },
    db: {
      nombreEsc:    esc(body.patient.name),
      emailEsc:     esc(body.patient.email),
      telefonoEsc:  esc(body.patient.phone),
      servicioEsc:  esc(body.service),
      razonEsc:     esc(body.reason),
      clienteId:    body.clienteId || 1,
      fecha:        body.date,
      horaInicio:   body.time,
      horaFin:      `${pad(endDate.getHours())}:${pad(endDate.getMinutes())}:00`,
      origen:       body.origen || 'web',
      esNuevo:      body.patient.newPatient ? 1 : 0
    },
    isValid: true
  }
}];

const booking = $('Validar y Preparar Datos').item.json;
const event = $('Crear Evento Google Calendar').item.json;

const fechaFormateada = new Date(booking.date + 'T00:00:00').toLocaleDateString('es-ES', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const msgProfesional = `✅ *Nueva cita confirmada*

👤 *Paciente:* ${booking.patient.name}
📱 *Teléfono:* ${booking.patient.phone}
📧 *Email:* ${booking.patient.email || '—'}

📅 *Fecha:* ${fechaFormateada}
🕐 *Hora:* ${booking.time}
📋 *Servicio:* ${booking.service}
📝 *Motivo:* ${booking.reason || 'No especificado'}

${booking.patient.newPatient ? '🆕 Paciente nuevo' : '🔄 Paciente habitual'}

_Evento añadido a Google Calendar y guardado en base de datos._`;

const msgPaciente = `✅ *¡Tu cita está confirmada!*

📅 ${fechaFormateada}
🕐 ${booking.time}
📋 ${booking.service}

_Recibirás un recordatorio 24h antes. Si necesitas cancelar, responde a este mensaje._`;

return [{
  json: { ...booking, msgProfesional, msgPaciente, eventId: event.id, eventLink: event.htmlLink }
}];
